def derive_team_routes(team_config: dict[str, Any]) -> dict[str, set[str]]:
    """Derive intra-team routes from team definitions.

    Every member of a team (including lead) can communicate with every other
    member of the same team. An agent in multiple teams gets the union of all
    team-based routes.
    """
    routes: dict[str, set[str]] = {}
    for team in team_config.get("teams", []):
        team_members = set(team.get("members", []))
        lead = team.get("lead", "")
        if lead:
            team_members.add(lead)
        for member in team_members:
            routes.setdefault(member, set()).update(team_members - {member})
    return routes


def get_team_members(team_id: str) -> set[str]:
    """Return all members (including lead) for a given team ID."""
    if TEAM_CONFIG is None:
        return set()
    for team in TEAM_CONFIG.get("teams", []):
        if team.get("id") == team_id:
            members = set(team.get("members", []))
            lead = team.get("lead", "")
            if lead:
                members.add(lead)
            return members
    return set()


