    task_id: str,
    result_summary: str = "",
    result_code: str = "success",
    evidence_type: str = "",
    evidence_ref: str = "",
) -> str:
    """Report task completion with evidence."""
    if _agent_id is None:
        return json.dumps({"error": "Not registered. Call bridge_register first."})
    result = {"summary": result_summary} if result_summary else {}
    payload: dict = {
